void dpi_trace(int level, const char* format, ...) {
  if (level > DEBUG_LEVEL)
    return;
  if (!sim_trace_enabled())
    return;
  va_list va;
	va_start(va, format);
	vprintf(format, va);
	va_end(va);
}

void dpi_trace_start() {
  sim_trace_enable(true);
}

void dpi_trace_stop() {
  sim_trace_enable(false);
}

