int generate_rand_mask(int mask) {
  int result = 0;
  int m = mask;
  for (int i = 0; i < 4; i++) {
    int bit = m & 0b1;
    int rand_bit = generate_rand(0, bit);
    result |= (rand_bit << i);
    m = m >> 1;
