uint_fast16_t f16_classify(float16_t a) {
  union ui16_f16 uA;
  uint_fast16_t uiA;

  uA.f = a;
  uiA = uA.ui;

  uint_fast16_t infOrNaN = expF16UI(uiA) == 0x1F;
  uint_fast16_t subnormalOrZero = expF16UI(uiA) == 0;
