        if (!warp.tmask.test(t))
          continue;
        auto is_pred = rs1_data[t].i & 0x1;
        if (is_pred) {
          has_vote_true = true;
          ballot |= (Word(1) << t);
        } else {
          has_vote_false = true;
        }
      }
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        switch (vote_type) {
        case VoteType::ALL:
          rd_data[t].i = !has_vote_false;
          break;
        case VoteType::ANY:
          rd_data[t].i = has_vote_true;
          break;
        case VoteType::UNI:
          rd_data[t].i = !has_vote_true || !has_vote_false;
          break;
        case VoteType::BAL:
          rd_data[t].i = ballot;
          break;
        default:
          std::abort();
        }
      }
      rd_write = true;
