    [&](ShflType shfl_type) {
      for (uint32_t t = thread_start; t < num_threads; ++t) {
        if (!warp.tmask.test(t))
          continue;
        auto bc  = rs2_data[t].i;
        int bval = (bc >>  0) & 0x3f;
        int cval = (bc >>  6) & 0x3f;
        int mask = (bc >> 12) & 0x3f;
        int maxLane = (t & mask) | (cval & ~mask);
        int minLane = (t & mask);
        int lane = 0;
        int pval = 0;
        switch (shfl_type) {
        case ShflType::UP: {
          lane = t - bval;
          pval = (lane >= minLane);
        } break;
        case ShflType::DOWN: {
          lane = t + bval;
          pval = (lane <= maxLane);
        } break;
        case ShflType::BFLY: {
          lane = t ^ bval;
          pval = (lane <= maxLane);
        } break;
        case ShflType::IDX: {
          lane = minLane | (bval & ~mask);
          pval = (lane <= maxLane);
        } break;
        default:
          std::abort();
        }
        if (!pval)
          lane = t;
        if (lane < num_threads) {
          rd_data[t].i = rs1_data[lane].i;
        } else {
          rd_data[t].i = rs1_data[t].i;
        }
      }
      rd_write = true;
